import base64
from enum import IntEnum
import io
from typing import TypedDict
import zlib

import numpy as np
import torch
from torch import nn


_POLICY_PACK_B64 = """\










""".replace("\n", "")





class TaskId(IntEnum):
    """Stable task identifiers shared across training and deployment."""

    EMPTY = 0
    LAVA_GAP = 1
    FOUR_ROOMS = 2
    MEMORY = 3
    DYNAMIC_OBSTACLES = 4
    DOOR_KEY = 5


ENV_NAME_TO_TASK_ID: dict[str, TaskId] = {
    "MiniGrid-Empty-8x8-v0": TaskId.EMPTY,
    "MiniGrid-LavaGapS7-v0": TaskId.LAVA_GAP,
    "MiniGrid-FourRooms-v0": TaskId.FOUR_ROOMS,
    "MiniGrid-MemoryS13Random-v0": TaskId.MEMORY,
    "MiniGrid-Dynamic-Obstacles-6x6-v0": TaskId.DYNAMIC_OBSTACLES,
    "MiniGrid-DoorKey-8x8-v0": TaskId.DOOR_KEY,
}

MISSION_TO_TASK_ID: dict[str, TaskId] = {
    "avoid the lava and get to the green goal square": TaskId.LAVA_GAP,
    "reach the goal": TaskId.FOUR_ROOMS,
    "go to the matching object at the end of the hallway": TaskId.MEMORY,
    "use the key to open the door and then get to the goal": TaskId.DOOR_KEY,
}


def infer_task_id_from_observation(obs: dict) -> TaskId:
    """Infer the deployment task id from a raw MiniGrid observation.

    Args:
        obs: Observation dictionary containing at least `mission` and `image`.

    Returns:
        The inferred task identifier used by the bundled policy.

    Raises:
        ValueError: If the mission string is not supported by this submission.
    """

    mission = obs["mission"]
    if mission == "get to the green goal square":
        object_ids = set(int(value) for value in np.asarray(obs["image"])[..., 0].reshape(-1).tolist())
        if 6 in object_ids:
            return TaskId.DYNAMIC_OBSTACLES
        return TaskId.EMPTY

    if mission not in MISSION_TO_TASK_ID:
        raise ValueError(f"Unsupported mission: {mission!r}")
    return MISSION_TO_TASK_ID[mission]




class MiniGridAction(IntEnum):
    """Subset of MiniGrid actions emitted by the bundled policy."""

    LEFT = 0
    RIGHT = 1
    FORWARD = 2
    PICKUP = 3
    TOGGLE = 5


DEFAULT_POLICY_ACTION_IDS: tuple[int, ...] = (
    int(MiniGridAction.LEFT),
    int(MiniGridAction.RIGHT),
    int(MiniGridAction.FORWARD),
)
DOORKEY_POLICY_ACTION_IDS: tuple[int, ...] = (
    int(MiniGridAction.LEFT),
    int(MiniGridAction.RIGHT),
    int(MiniGridAction.FORWARD),
    int(MiniGridAction.PICKUP),
    int(MiniGridAction.TOGGLE),
)


def allowed_env_actions_for_task(task_id: int) -> tuple[int, ...]:
    """Return the environment action ids valid for a given task.

    Args:
        task_id: Stable task identifier for the current environment.

    Returns:
        The tuple of environment action ids allowed for that task.
    """

    if task_id == int(TaskId.DOOR_KEY):
        return DOORKEY_POLICY_ACTION_IDS
    return DEFAULT_POLICY_ACTION_IDS


def mask_policy_logits(
    logits: torch.Tensor,
    task_ids: torch.Tensor,
    action_ids: tuple[int, ...],
) -> torch.Tensor:
    """Mask invalid task-specific actions before greedy action selection.

    Args:
        logits: Policy logits indexed over `action_ids`.
        task_ids: Task ids aligned with the leading dimensions of `logits`.
        action_ids: Environment action id represented by each logit column.

    Returns:
        A tensor shaped like `logits` with invalid actions set to a large
        negative value.
    """

    flat_logits = logits.reshape(-1, logits.shape[-1])
    flat_task_ids = task_ids.reshape(-1)
    mask = torch.zeros_like(flat_logits, dtype=torch.bool)

    for row_index in range(flat_logits.shape[0]):
        allowed_actions = allowed_env_actions_for_task(int(flat_task_ids[row_index].item()))
        for action_index, env_action in enumerate(action_ids):
            if env_action in allowed_actions:
                mask[row_index, action_index] = True

    masked = flat_logits.masked_fill(~mask, -1e9)
    return masked.reshape_as(logits)


class TrainConfig:
    """Minimal inference-only config shim for the bundled policy.

    Attributes:
        obs_embed_dim: Embedding width for object, color, and state channels.
        direction_embed_dim: Embedding width for agent direction.
        task_embed_dim: Embedding width for task ids.
        hidden_dim: Shared latent width used by the policy network.
        cnn_channels: Convolution widths for the visual encoder.
        use_recurrence: Whether the policy includes recurrent state.
        task_recurrent_task_ids: Task ids with task-specific recurrent modules.
        use_task_heads: Whether the policy uses per-task policy heads.
        use_task_adapters: Whether the policy uses per-task latent adapters.
        action_ids: Environment action ids represented by policy logits.
        action_dim: Number of policy logits produced per forward pass.
        task_vocab_size: Number of task embeddings stored in the checkpoint.
    """

    def __init__(self, **kwargs):
        self.obs_embed_dim = int(kwargs.get('obs_embed_dim', 16))
        self.direction_embed_dim = int(kwargs.get('direction_embed_dim', 4))
        self.task_embed_dim = int(kwargs.get('task_embed_dim', 8))
        self.hidden_dim = int(kwargs.get('hidden_dim', 128))
        self.cnn_channels = tuple(kwargs.get('cnn_channels', (64, 64)))
        self.use_recurrence = bool(kwargs.get('use_recurrence', True))
        self.task_recurrent_task_ids = tuple(kwargs.get('task_recurrent_task_ids', ()))
        self.use_task_heads = bool(kwargs.get('use_task_heads', False))
        self.use_task_adapters = bool(kwargs.get('use_task_adapters', False))
        self.action_ids = tuple(kwargs.get('action_ids', DEFAULT_POLICY_ACTION_IDS))

        action_dim = kwargs.get('action_dim')
        if action_dim is None:
            self.action_dim = len(self.action_ids)
        else:
            self.action_dim = int(action_dim)

        task_vocab_size = kwargs.get('task_vocab_size')
        if task_vocab_size is None:
            env_names = kwargs.get('env_names')
            if env_names is None:
                raise ValueError('TrainConfig requires task_vocab_size or env_names for inference.')
            max_task_id = max(int(ENV_NAME_TO_TASK_ID[env_name]) for env_name in env_names)
            self.task_vocab_size = max_task_id + 1
        else:
            self.task_vocab_size = int(task_vocab_size)




class ObsBatch(TypedDict):
    """Tensorized MiniGrid observation batch expected by the policy."""

    obj: torch.Tensor
    color: torch.Tensor
    state: torch.Tensor
    direction: torch.Tensor
    task_id: torch.Tensor


def obs_to_tensors(obs: dict, device: torch.device) -> ObsBatch:
    """Convert a batched observation dict into model input tensors.

    Args:
        obs: Observation batch containing image, direction, and task id fields.
        device: Torch device that should own the returned tensors.

    Returns:
        A tensor batch split into typed object, color, state, direction, and
        task-id fields.
    """

    image = torch.as_tensor(obs["image"], device=device, dtype=torch.long)
    direction = torch.as_tensor(obs["direction"], device=device, dtype=torch.long)
    task_id = torch.as_tensor(obs["task_id"], device=device, dtype=torch.long).squeeze(-1)

    return {
        "obj": image[..., 0],
        "color": image[..., 1],
        "state": image[..., 2],
        "direction": direction,
        "task_id": task_id,
    }



class MultiTaskNavActorCritic(nn.Module):
    """Shared multi-task actor-critic used by the bundled experts."""

    def __init__(self, config: TrainConfig):
        super().__init__()
        embed_dim = config.obs_embed_dim
        self.object_embedding = nn.Embedding(11, embed_dim)
        self.color_embedding = nn.Embedding(6, embed_dim)
        self.state_embedding = nn.Embedding(3, embed_dim)
        self.direction_embedding = nn.Embedding(4, config.direction_embed_dim)
        self.task_embedding = nn.Embedding(config.task_vocab_size, config.task_embed_dim)

        input_channels = embed_dim * 3
        conv_a, conv_b = config.cnn_channels
        self.encoder = nn.Sequential(
            nn.Conv2d(input_channels, conv_a, kernel_size=3, padding=1),
            nn.ReLU(),
            nn.Conv2d(conv_a, conv_b, kernel_size=3, padding=1),
            nn.ReLU(),
            nn.Flatten(),
        )

        spatial_dim = conv_b * 7 * 7
        fused_dim = spatial_dim + config.direction_embed_dim + config.task_embed_dim
        self.pre_recurrent = nn.Sequential(
            nn.Linear(fused_dim, config.hidden_dim),
            nn.ReLU(),
        )
        self.use_recurrence = config.use_recurrence
        self.task_recurrent_task_ids = {int(task_id) for task_id in config.task_recurrent_task_ids}
        if self.use_recurrence:
            self.recurrent = nn.GRU(
                input_size=config.hidden_dim,
                hidden_size=config.hidden_dim,
                batch_first=False,
            )
            self.task_recurrents = nn.ModuleDict(
                {
                    str(task_id): nn.GRU(
                        input_size=config.hidden_dim,
                        hidden_size=config.hidden_dim,
                        batch_first=False,
                    )
                    for task_id in sorted(self.task_recurrent_task_ids)
                }
            )
        self.post_recurrent = nn.Sequential(
            nn.Linear(config.hidden_dim, config.hidden_dim),
            nn.ReLU(),
        )
        self.use_task_adapters = config.use_task_adapters
        if self.use_task_adapters:
            self.task_adapters = nn.ModuleList(
                [
                    nn.Sequential(
                        nn.Linear(config.hidden_dim, config.hidden_dim),
                        nn.ReLU(),
                    )
                    for _ in range(config.task_vocab_size)
                ]
            )
        self.use_task_heads = config.use_task_heads
        if self.use_task_heads:
            self.policy_heads = nn.ModuleList(
                [nn.Linear(config.hidden_dim, config.action_dim) for _ in range(config.task_vocab_size)]
            )
        else:
            self.policy_head = nn.Linear(config.hidden_dim, config.action_dim)
        self.value_head = nn.Linear(config.hidden_dim, 1)

    def _policy_logits(self, latent: torch.Tensor, task_ids: torch.Tensor):

        if not self.use_task_heads:
            return self.policy_head(latent)

        flat_latent = latent.reshape(-1, latent.shape[-1])
        flat_task_ids = task_ids.reshape(-1)
        flat_logits = torch.zeros(
            (flat_latent.shape[0], self.policy_heads[0].out_features),
            device=flat_latent.device,
            dtype=flat_latent.dtype,
        )
        for task_id, head in enumerate(self.policy_heads):
            task_mask = flat_task_ids == task_id
            if torch.any(task_mask):
                flat_logits[task_mask] = head(flat_latent[task_mask])
        return flat_logits.reshape(*latent.shape[:-1], -1)

    def _adapt_latent(self, latent: torch.Tensor, task_ids: torch.Tensor):

        if not self.use_task_adapters:
            return self.post_recurrent(latent)

        flat_latent = latent.reshape(-1, latent.shape[-1])
        flat_task_ids = task_ids.reshape(-1)
        adapted = torch.zeros_like(flat_latent)
        for task_id, adapter in enumerate(self.task_adapters):
            task_mask = flat_task_ids == task_id
            if torch.any(task_mask):
                adapted[task_mask] = adapter(flat_latent[task_mask])
        return adapted.reshape_as(latent)

    def encode(self, obs: ObsBatch):
        """Encode one observation batch into the shared latent space.

        Args:
            obs: Tensorized MiniGrid observation batch.

        Returns:
            Latent features before recurrent processing.
        """

        object_feat = self.object_embedding(obs["obj"])
        color_feat = self.color_embedding(obs["color"])
        state_feat = self.state_embedding(obs["state"])

        features = torch.cat([object_feat, color_feat, state_feat], dim=-1)
        features = features.permute(0, 3, 1, 2)
        spatial = self.encoder(features)

        direction = self.direction_embedding(obs["direction"])
        task = self.task_embedding(obs["task_id"])
        latent = torch.cat([spatial, direction, task], dim=-1)
        return self.pre_recurrent(latent)

    def initial_hidden(self, batch_size: int, device: torch.device):
        """Create an initial recurrent hidden state tensor.

        Args:
            batch_size: Number of parallel environments in the batch.
            device: Torch device for the returned tensor.

        Returns:
            Zero-initialized recurrent hidden state.
        """

        return torch.zeros(1, batch_size, self.value_head.in_features, device=device)

    def _forward_recurrent_step(
        self,
        latent: torch.Tensor,
        task_ids: torch.Tensor,
        hidden_state,
    ):

        if hidden_state is None:
            hidden_state = self.initial_hidden(batch_size=latent.shape[0], device=latent.device)

        if not self.task_recurrent_task_ids:
            recurrent_output, next_hidden = self.recurrent(latent.unsqueeze(0), hidden_state)
            return recurrent_output.squeeze(0), next_hidden

        next_hidden = hidden_state.clone()
        outputs = torch.zeros_like(latent)
        assigned_mask = torch.zeros(latent.shape[0], device=latent.device, dtype=torch.bool)

        for task_id in sorted(self.task_recurrent_task_ids):
            task_mask = task_ids == task_id
            if not torch.any(task_mask):
                continue
            recurrent_output, updated_hidden = self.task_recurrents[str(task_id)](
                latent[task_mask].unsqueeze(0),
                hidden_state[:, task_mask, :],
            )
            outputs[task_mask] = recurrent_output.squeeze(0)
            next_hidden[:, task_mask, :] = updated_hidden
            assigned_mask |= task_mask

        shared_mask = ~assigned_mask
        if torch.any(shared_mask):
            recurrent_output, updated_hidden = self.recurrent(
                latent[shared_mask].unsqueeze(0),
                hidden_state[:, shared_mask, :],
            )
            outputs[shared_mask] = recurrent_output.squeeze(0)
            next_hidden[:, shared_mask, :] = updated_hidden

        return outputs, next_hidden

    def forward_step(
        self,
        obs: ObsBatch,
        hidden_state=None,
    ):
        """Run one inference step and update recurrent state.

        Args:
            obs: Tensorized MiniGrid observation batch.
            hidden_state: Previous recurrent hidden state or `None`.

        Returns:
            Tuple of policy logits, value estimate, and next hidden state.
        """

        latent = self.encode(obs)
        next_hidden = hidden_state

        if self.use_recurrence:
            latent, next_hidden = self._forward_recurrent_step(
                latent=latent,
                task_ids=obs["task_id"],
                hidden_state=hidden_state,
            )

        latent = self._adapt_latent(latent, obs["task_id"])
        logits = self._policy_logits(latent, obs["task_id"])
        value = self.value_head(latent).squeeze(-1)
        return logits, value, next_hidden

    def forward_sequence(
        self,
        obs: ObsBatch,
        episode_starts: torch.Tensor,
        initial_hidden=None,
    ):
        """Run the policy over a full time-major rollout batch.

        Args:
            obs: Tensorized sequence batch with shape `[T, B, ...]`.
            episode_starts: Binary indicators used to reset recurrent state.
            initial_hidden: Optional initial recurrent hidden state.

        Returns:
            Tuple of sequence logits and sequence value predictions.
        """

        time_steps = obs["obj"].shape[0]
        batch_size = obs["obj"].shape[1]
        flat_obs: ObsBatch = {
            "obj": obs["obj"].reshape(-1, 7, 7),
            "color": obs["color"].reshape(-1, 7, 7),
            "state": obs["state"].reshape(-1, 7, 7),
            "direction": obs["direction"].reshape(-1),
            "task_id": obs["task_id"].reshape(-1),
        }
        encoded = self.encode(flat_obs).reshape(time_steps, batch_size, -1)

        if not self.use_recurrence:
            latent = self.post_recurrent(encoded.reshape(-1, encoded.shape[-1])).reshape(
                time_steps,
                batch_size,
                -1,
            )
            logits = self.policy_head(latent)
            value = self.value_head(latent).squeeze(-1)
            return logits, value

        if initial_hidden is None:
            hidden = self.initial_hidden(batch_size=batch_size, device=encoded.device)
        else:
            hidden = initial_hidden

        outputs: list[torch.Tensor] = []
        for step in range(time_steps):
            reset_mask = (1.0 - episode_starts[step]).view(1, batch_size, 1)
            hidden = hidden * reset_mask
            recurrent_output, hidden = self._forward_recurrent_step(
                latent=encoded[step],
                task_ids=obs["task_id"][step],
                hidden_state=hidden,
            )
            outputs.append(recurrent_output)

        latent = torch.stack(outputs, dim=0)
        latent = self._adapt_latent(latent, obs["task_id"])
        logits = self._policy_logits(latent, obs["task_id"])
        value = self.value_head(latent).squeeze(-1)
        return logits, value

    def forward(self, obs: ObsBatch):
        """Run a stateless forward pass for compatibility with `nn.Module`.

        Args:
            obs: Tensorized MiniGrid observation batch.

        Returns:
            Tuple of policy logits and value estimates.
        """

        logits, value, _ = self.forward_step(obs)
        return logits, value




def get_model():
    """Decode the compact payload and reconstruct bundled expert checkpoints.

    Returns:
        A mapping containing the reconstructed base and DoorKey expert payloads.
    """

    compact = torch.load(
        io.BytesIO(zlib.decompress(base64.b64decode(_POLICY_PACK_B64))),
        map_location='cpu',
    )

    base_config = dict(compact['base_config'])
    base_state = dict(compact['base_state'])
    base_payload = {
        'config': base_config,
        'model_state': base_state,
    }

    doorkey_config = dict(base_config)
    doorkey_config.update(compact['doorkey_overrides'])
    doorkey_state = {}
    for name, tensor in base_state.items():
        if name == 'task_embedding.weight':
            extra_row = compact['extra']['task_embedding_extra_row'].to(dtype=tensor.dtype)
            doorkey_state[name] = torch.cat([tensor, extra_row.unsqueeze(0)], dim=0)
        elif name == 'policy_head.weight':
            doorkey_state[name] = compact['extra']['policy_head.weight'].to(dtype=tensor.dtype)
        elif name == 'policy_head.bias':
            doorkey_state[name] = compact['extra']['policy_head.bias'].to(dtype=tensor.dtype)
        else:
            scale = compact['delta_scale'][name]
            delta = compact['delta_q'][name].to(dtype=torch.float32) * float(scale)
            doorkey_state[name] = (tensor.to(dtype=torch.float32) + delta).to(dtype=tensor.dtype)

    doorkey_payload = {
        'config': doorkey_config,
        'model_state': doorkey_state,
    }
    return {'base': base_payload, 'doorkey': doorkey_payload}


class _LoadedPolicyExpert:
    """Loaded expert bundle with recurrent state used during deployment."""

    def __init__(self, config, model, hidden_state, episode_starts):
        self.config = config
        self.model = model
        self.hidden_state = hidden_state
        self.episode_starts = episode_starts

    def reset(self):
        self.hidden_state.zero_()
        self.episode_starts.fill_(1.0)


class NavigationPolicyController:
    """Inference controller that selects and runs the correct expert."""

    def __init__(self):
        self.device = torch.device('cpu')
        payload = get_model()
        self.base_expert = self._load_expert(payload['base'])
        self.doorkey_expert = self._load_expert(payload['doorkey'])
        self.task_id = None

    def _load_expert(self, payload):
        """Instantiate one expert model from a serialized payload."""

        config = TrainConfig(**payload['config'])
        model = MultiTaskNavActorCritic(config).to(self.device)
        model.load_state_dict(payload['model_state'])
        model.eval()
        hidden_state = model.initial_hidden(batch_size=1, device=self.device)
        episode_starts = torch.ones(1, device=self.device, dtype=torch.float32)
        return _LoadedPolicyExpert(
            config=config,
            model=model,
            hidden_state=hidden_state,
            episode_starts=episode_starts,
        )

    def _select_expert(self, task_id):
        """Choose the bundled expert associated with `task_id`."""

        if task_id == int(TaskId.DOOR_KEY):
            return self.doorkey_expert
        return self.base_expert

    def reset(self):
        """Reset all expert recurrent state for a new episode."""

        self.base_expert.reset()
        self.doorkey_expert.reset()
        self.task_id = None

    def act(self, obs):
        """Run the selected expert and return the greedy environment action.

        Args:
            obs: Raw MiniGrid observation dictionary from the environment.

        Returns:
            Integer environment action compatible with MiniGrid.

        Raises:
            ValueError: If the observation mission is unsupported.
        """

        # Keep the inferred task identity fixed within an episode. Dynamic
        # Obstacles can temporarily hide all balls from the local 7x7 view,
        # which would otherwise cause a spurious downgrade to Empty.
        if self.task_id is None:
            self.task_id = int(infer_task_id_from_observation(obs))

        expert = self._select_expert(self.task_id)
        batched_obs = {
            'image': obs['image'][None, ...],
            'direction': np.asarray([obs['direction']], dtype=np.int64),
            'task_id': np.asarray([[self.task_id]], dtype=np.int64),
        }
        tensors = obs_to_tensors(batched_obs, device=self.device)
        with torch.no_grad():
            expert.hidden_state = expert.hidden_state * (1.0 - expert.episode_starts).view(1, 1, 1)
            logits, _, expert.hidden_state = expert.model.forward_step(
                tensors,
                hidden_state=expert.hidden_state,
            )
            masked_logits = mask_policy_logits(
                logits=logits,
                task_ids=tensors['task_id'],
                action_ids=expert.config.action_ids,
            )
            policy_action = torch.argmax(masked_logits, dim=-1).item()

        expert.episode_starts.fill_(0.0)
        return int(expert.config.action_ids[policy_action])


class Agent:
    """Coursemology submission wrapper exposing the required agent API."""

    def __init__(self, obs_space, action_space):
        """Initialize the submission agent and eagerly load the policy.

        Args:
            obs_space: Environment observation space passed by Coursemology.
            action_space: Environment action space passed by Coursemology.
        """

        self.obs_space = obs_space
        self.action_space = action_space
        self.controller = NavigationPolicyController()
        self.controller.reset()

    def reset(self):
        self.controller.reset()

    def act(self, obs):
        return self.controller.act(obs)
